query:
{
  gkeClusters(
    where: {
      OR: [
        { currentMasterVersion_MATCHES: "^1\\.32(\\.|-|$)" }
        { currentNodeVersion_MATCHES: "^1\\.32(\\.|-|$)" }
        { nodePools_SOME: { version_MATCHES: "^1\\.32(\\.|-|$)" } }
      ]
    }
  ) {
    ...AssetFragment
    currentMasterVersion
    currentNodeVersion
    releaseChannel
    nodePools {
      name
      version
      managementAutoUpgrade
    }
  }
}
